<template>
	<div class="__l_m">
		<div class="__l_w">
			<navi-bar></navi-bar>
			<div style="position: relative; height: 100%">
				<transition :enter-active-class="'animated faster '+ transitionClass.ec" :leave-active-class="'animated faster '+ transitionClass.lc">
					<router-view></router-view>
				</transition>
			</div>
		</div>
	</div>
</template>

<script>
import NaviBar from '@/components/NaviBar.vue';

import 'vue-awesome/icons/leaf';
import 'vue-awesome/icons/home';
import 'vue-awesome/icons/chart-bar';


export default {
	components: {
		NaviBar
	},
	data() {
		return {
			isShowSideMenu: false,
			transitionClass: { ec: '', lc: '' }
		}
	},
	methods: {
		goLink(link) {
			this.isShowSideMenu = false;
			this.$router.push({ name: link });
		}
	},
	watch: {
		'$route'(n,o) {
			if (n.meta.ix > o.meta.ix) {
				this.transitionClass = n.meta.transitionf;
			} else {
				this.transitionClass = n.meta.transitionb;
			}
		}
	}
}
</script>

<style scoped>
.__l_m { height: 100%; position: absolute; top: 0; right: 0; left: 0; bottom: 0; }
.__l_m .__l_w { height: 100%; display: grid; grid-template-rows: 52px auto; }
</style>
