<template>
	<div class="__app" ref="appContainer">
		<transition enter-active-class="ianimated ifaster islideInRight" leave-active-class="ianimated ifaster islideOutLeft">
			<router-view></router-view>
		</transition>
	</div>
</template>

<script>
export default {
	methods: {
	},
	created() {
		//this.$http.defaults.baseURL = 'http://127.0.0.1:8000/api';
	},
	mounted() {
		const resizeObserver = new ResizeObserver(() => {
			this.$store.dispatch('updateClient', { width: this.$refs.appContainer.clientWidth, height: this.$refs.appContainer.clientHeight });
		});
		resizeObserver.observe(this.$refs.appContainer);
	}
}
</script>


